<template>
  <div class="entry">
    <iframe class="entry-iframe" :src=params></iframe>
  </div>
</template>

<script setup>
import { useRouter } from 'vue-router'
import { isMobileDevice } from '@/utils'
const route = useRoute()


const router = useRouter()
const query = router.currentRoute.value.query
const params = ref("/minid5Lottery/game?" + new URLSearchParams(query).toString())

if (isMobileDevice()) {
  params.value = "/game?" + new URLSearchParams(query).toString()
  router.replace(params.value);
}

